/// <summary>
/// extension class for form datasource LedgerJournalTransVendPaym, LedgerJournalTrans
/// </summary>
[ExtensionOf(formDataSourceStr(LedgerJournalTransVendPaym, LedgerJournalTrans))]
internal final class ETGLedgerJournalTransVendPaym_FormDS_Extension
{
}

Method.Source:
/// <summary>
/// update design for custom fields
/// </summary>
/// <returns>int</returns>
public int active()
{
    boolean showTermoFields, isAdvPrepayment;
    int ret;

    ret = next active();

    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        LedgerJournalTrans ledgerJournalTrans = this.cursor();

        showTermoFields = true;
        if(ledgerJournalTrans.Prepayment == NoYes::Yes)
        {
            isAdvPrepayment = true;
        }
    }
    this.object(fieldNum(LedgerJournalTrans, ETGTERMONumber)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGMotherTERMONumber)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGCustVendInvoiceId)).visible(showTermoFields);
    this.object(fieldNum(LedgerJournalTrans, ETGTERMONumber)).allowEdit(showTermoFields && isAdvPrepayment);

    return ret;
}
